/**
 * AI Pricing Model Service
 * 
 * Implements the decision logic for the learning-based pricing engine.
 * Initial Strategy: Multi-Armed Bandit (Epsilon-Greedy) with Fallback.
 */
import prisma from '../config/db.js';
import featureBuilder from './featureBuilder.js';
import { eventBus, EVENTS } from '../services/eventBus.js';

// Configuration for the "Arms" (candidate multipliers)
const CANDIDATE_MULTIPLIERS = [0.90, 1.0, 1.05, 1.10, 1.20];
const EPSILON = 0.15; // 15% exploration
const MIN_CONFIDENCE = 0.65;

export const pricingModelService = {
  /**
   * Predicts the optimal multiplier for a given context
   * 
   * @param {Object} context 
   * @returns {Object} prediction
   */
  getOptimalMultiplier: async (context) => {
    const { sessionId, userId } = context;
    const features = featureBuilder.buildFeatures(context);
    const contextHash = featureBuilder.generateContextHash(features);

    try {
      // 1. Session + Date Consistency: Lock multiplier per session/roomType/date for 15 mins
      const dateKey = features.date.toISOString().split('T')[0];
      const cachedPrediction = await prisma.pricingPrediction.findFirst({
        where: { 
          contextHash, 
          createdAt: { gte: new Date(Date.now() - 15 * 60 * 1000) },
          source: { in: ['AI_EXPLOITATION', 'AI_EXPLORATION'] },
          // Ensure same date gets same price to prevent user shock
          id: { in: (await prisma.pricingFeatureLog.findMany({
            where: { date: features.date },
            select: { id: true }
          })).map(l => l.id) } // This is a bit complex, let's simplify to contextHash + date logic
        },
        orderBy: { createdAt: 'desc' }
      });

      // Simpler Session+Date Lock
      const sessionLock = await prisma.pricingPrediction.findFirst({
        where: {
          contextHash,
          createdAt: { gte: new Date(Date.now() - 15 * 60 * 1000) },
          source: { in: ['AI_EXPLOITATION', 'AI_EXPLORATION'] }
        },
        orderBy: { createdAt: 'desc' }
      });

      if (sessionLock) {
        return {
          multiplier: sessionLock.multiplier,
          confidence: sessionLock.confidence,
          modelVersion: sessionLock.modelVersion,
          source: 'AI_SESSION_DATE_LOCKED',
          predictionId: sessionLock.id
        };
      }

      // 2. Cold-Start Guard: Fallback to rules if we have < 30 samples for this context
      const feedbackCount = await prisma.pricingFeedback.count({
        where: { prediction: { contextHash } }
      });

      if (feedbackCount < 30) {
        return { multiplier: 1.0, confidence: 0.1, modelVersion: 'cold_start', source: 'RULE_FALLBACK' };
      }

      // 3. Stratified Exploration & Arm Starvation Protection
      const bucketSeed = userId || sessionId || Math.random().toString();
      const bucket = Math.abs(featureBuilder.generateContextHash({ id: bucketSeed }).split('').reduce((a, b) => a + b.charCodeAt(0), 0)) % 100;

      let isExploring = bucket < EPSILON * 100;
      let selectedMultiplier;
      let confidence = 0.8;

      // Arm Starvation Protection: Check if any arm is severely under-sampled
      const armStats = await prisma.pricingPrediction.groupBy({
        by: ['multiplier'],
        _count: true,
        where: { createdAt: { gte: new Date(Date.now() - 24 * 60 * 60 * 1000) } }
      });

      const underSampledArm = CANDIDATE_MULTIPLIERS.find(m => {
        const stat = armStats.find(s => s.multiplier === m);
        return !stat || stat._count < 10; // minThreshold = 10
      });

      if (underSampledArm && isExploring) {
        selectedMultiplier = underSampledArm;
        confidence = 0.45; // Forced exploration
      } else if (isExploring) {
        selectedMultiplier = CANDIDATE_MULTIPLIERS[Math.floor(Math.random() * CANDIDATE_MULTIPLIERS.length)];
        confidence = 0.5;
      } else {
        // Exploit logic (simulate bandit arm selection)
        if (features.demandScore > 0.8) selectedMultiplier = 1.15;
        else if (features.demandScore < 0.3) selectedMultiplier = 0.95;
        else selectedMultiplier = 1.0;
        confidence = 0.9;
      }

      // 4. Price Elasticity Ceiling: Hard cap AI multiplier at 1.25 (Safety layer)
      selectedMultiplier = Math.min(selectedMultiplier, 1.25);

      // 4. Save Prediction and log initial NOT_BOOKED exposure
      const prediction = await prisma.pricingPrediction.create({
        data: {
          contextHash,
          multiplier: selectedMultiplier,
          confidence,
          modelVersion: 'bandit_v1_beta',
          source: isExploring ? 'AI_EXPLORATION' : 'AI_EXPLOITATION'
        }
      });

      // Log exposure immediately as NOT_BOOKED (Exposure event)
      // This will be updated to BOOKED if the user completes the transaction
      await prisma.pricingFeedback.create({
        data: {
          predictionId: prediction.id,
          outcome: 'NOT_BOOKED',
          revenue: 0
        }
      });

      // 5. Broadcast AI Transparency Event
      const reasoning = isExploring 
        ? `Exploration mode (Epsilon-Greedy): Testing ${selectedMultiplier}x to collect new signals.`
        : features.demandScore > 0.8 
          ? `High demand detected (${(features.demandScore * 100).toFixed(0)}%). Increasing rates to optimize RevPAR.`
          : features.demandScore < 0.3 
            ? `Low demand detected (${(features.demandScore * 100).toFixed(0)}%). Dropping rates to stimulate volume.`
            : `Market demand stable. Maintaining optimal rates.`;

      eventBus.emitEvent('AI_PRICING_ADJUSTMENT', {
        hotelId: features.hotelId,
        roomTypeId: features.roomTypeId,
        multiplier: selectedMultiplier,
        confidence,
        reasoning,
        signals: {
          demand: features.demandScore,
          occupancy: features.occupancyRate,
          daysToCheckIn: features.daysToCheckIn
        }
      }, { source: 'AI_BANDIT_MODEL', entityId: prediction.id });

      return {
        multiplier: selectedMultiplier,
        confidence,
        modelVersion: prediction.modelVersion,
        source: prediction.source,
        predictionId: prediction.id
      };

    } catch (error) {
      console.error('[AI Pricing] Inference Error:', error);
      return { multiplier: 1.0, confidence: 0, modelVersion: 'fallback', source: 'RULE' };
    }
  },

  /**
   * Logs a feature set and prediction outcome to the feedback loop
   */
  logOutcome: async (predictionId, features, finalPrice, outcome, revenue = 0) => {
    try {
      await prisma.pricingFeatureLog.create({
        data: {
          hotelId: features.hotelId,
          roomTypeId: features.roomTypeId,
          date: features.date,
          basePrice: features.basePrice,
          finalPrice: finalPrice,
          demandScore: features.demandScore,
          occupancy: features.occupancyRate,
          daysToCheckIn: features.daysToCheckIn,
          dayOfWeek: features.dayOfWeek,
          segment: features.userSegment,
          device: features.device,
          wasBooked: outcome === 'BOOKED',
          revenue: outcome === 'BOOKED' ? revenue : 0 // Reward definition: revenue only on conversion
        }
      });

      if (predictionId) {
        // Update the initial NOT_BOOKED exposure record to BOOKED
        await prisma.pricingFeedback.updateMany({
          where: { predictionId, outcome: 'NOT_BOOKED' },
          data: {
            outcome,
            revenue: outcome === 'BOOKED' ? revenue : 0
          }
        });
      }
    } catch (error) {
      console.error('[AI Pricing] Feedback Logging Error:', error);
    }
  }
};

export default pricingModelService;

import prisma from '../config/db.js';
import { asyncHandler } from '../middleware/asyncHandler.js';
import { z } from 'zod';

// --- ZOD SCHEMAS ---

const analyticsQuerySchema = z.object({
  days: z.string().transform(Number).pipe(z.number().int().min(1).max(365)).optional().default('7'),
  hotelId: z.string().uuid().optional()
});

/** Build a date N days ago, set to midnight */
const daysAgo = (n) => {
  const d = new Date();
  d.setDate(d.getDate() - n);
  d.setHours(0, 0, 0, 0);
  return d;
};

/** Helper to get scope filter based on user role */
const getScopeFilter = (req) => {
  if (req.user.role === 'ADMIN') return {};
  return { hotel: { ownerId: req.user.id } };
};

const getHotelScopeFilter = (req) => {
  if (req.user.role === 'ADMIN') return { isDeleted: false };
  return { isDeleted: false, ownerId: req.user.id };
};

// ─── GET /api/v1/analytics/kpis ───────────────────────────────────────────────
export const getKpis = asyncHandler(async (req, res) => {
    const scope = getScopeFilter(req);
    const hotelScope = getHotelScopeFilter(req);

    console.log(`[Analytics] KPI request by ${req.user.id} (${req.user.role})`);

    const now        = new Date();
    const thisMonth  = new Date(now.getFullYear(), now.getMonth(), 1);
    const lastMonth  = new Date(now.getFullYear(), now.getMonth() - 1, 1);
    const lastMonthEnd = new Date(now.getFullYear(), now.getMonth(), 0, 23, 59, 59);

    // 1. Total revenue (all time) - ONLY for CONFIRMED/COMPLETED bookings
    const [revAll, revThis, revLast] = await Promise.all([
      prisma.booking.aggregate({ where: { ...scope, status: { in: ['CONFIRMED', 'COMPLETED'] } }, _sum: { totalAmount: true } }),
      prisma.booking.aggregate({ where: { ...scope, status: { in: ['CONFIRMED', 'COMPLETED'] }, createdAt: { gte: thisMonth } }, _sum: { totalAmount: true } }),
      prisma.booking.aggregate({ where: { ...scope, status: { in: ['CONFIRMED', 'COMPLETED'] }, createdAt: { gte: lastMonth, lte: lastMonthEnd } }, _sum: { totalAmount: true } }),
    ]);

    // 2. Booking counts
    const [bookingsAll, bookingsThis, bookingsLast, bookingsCancelled] = await Promise.all([
      prisma.booking.count({ where: { ...scope, status: { in: ['CONFIRMED', 'COMPLETED'] } } }),
      prisma.booking.count({ where: { ...scope, status: { in: ['CONFIRMED', 'COMPLETED'] }, createdAt: { gte: thisMonth } } }),
      prisma.booking.count({ where: { ...scope, status: { in: ['CONFIRMED', 'COMPLETED'] }, createdAt: { gte: lastMonth, lte: lastMonthEnd } } }),
      prisma.booking.count({ where: { ...scope, status: 'CANCELLED', createdAt: { gte: thisMonth } } }),
    ]);

    // 3. Live properties
    const [propertiesTotal, propertiesLive] = await Promise.all([
      prisma.hotel.count({ where: hotelScope }),
      prisma.hotel.count({ where: { ...hotelScope, status: 'ACTIVE' } }),
    ]);

    // 4. Cancellation rate this month
    const totalThisMonth  = bookingsThis + bookingsCancelled;
    const cancelRate = totalThisMonth > 0
      ? Math.round((bookingsCancelled / totalThisMonth) * 100)
      : 0;

    // 5. Compute MoM deltas
    const revThisVal  = revThis._sum.totalAmount  || 0;
    const revLastVal  = revLast._sum.totalAmount  || 0;
    const revDelta    = revLastVal > 0 ? ((revThisVal - revLastVal) / revLastVal * 100).toFixed(1) : null;

    const bkDelta     = bookingsLast > 0 ? ((bookingsThis - bookingsLast) / bookingsLast * 100).toFixed(1) : null;

    res.status(200).json({
      success: true,
      data: {
        revenue: {
          total:    revAll._sum.totalAmount || 0,
          thisMonth: revThisVal,
          delta:    revDelta,
          trend:    revDelta !== null ? (parseFloat(revDelta) >= 0 ? 'up' : 'down') : 'neutral',
        },
        bookings: {
          total:    bookingsAll,
          thisMonth: bookingsThis,
          active:   bookingsThis, // Explicitly aligned with Dashboard.jsx
          delta:    bkDelta,
          trend:    bkDelta !== null ? (parseFloat(bkDelta) >= 0 ? 'up' : 'down') : 'neutral',
        },
        properties: {
          total: propertiesTotal,
          live:  propertiesLive,
        },
        cancellation: {
          rate: cancelRate,
          count: bookingsCancelled,
          trend: cancelRate > 15 ? 'down' : 'up' // High cancellation is 'down' (bad)
        }
      },
      requestId: req.id
    });
});

// ─── GET /api/v1/analytics/revenue ────────────────────────────────────────────
export const getRevenueTrend = asyncHandler(async (req, res) => {
  const validation = analyticsQuerySchema.safeParse(req.query);
  if (!validation.success) {
    return res.status(422).json({ success: false, message: 'Validation failed', errors: validation.error.format(), requestId: req.id });
  }

  const { days, hotelId } = validation.data;
  const scope = getScopeFilter(req);
  const from = daysAgo(days);

    const where = {
      ...scope,
      status: { in: ['CONFIRMED', 'COMPLETED'] },
      createdAt: { gte: from },
      ...(hotelId ? { hotelId } : {}),
    };

    const bookings = await prisma.booking.findMany({
      where,
      select: { createdAt: true, totalAmount: true },
      orderBy: { createdAt: 'asc' },
    });

    // Aggregate by date
    const map = {};
    for (const b of bookings) {
      const date = b.createdAt.toISOString().split('T')[0];
      map[date] = (map[date] || 0) + b.totalAmount;
    }

    const series = Object.entries(map).map(([date, revenue]) => ({ date, revenue }));

    res.status(200).json({ success: true, data: series, requestId: req.id });
});

// ─── GET /api/v1/analytics/bookings ───────────────────────────────────────────
export const getBookingStats = asyncHandler(async (req, res) => {
  const validation = analyticsQuerySchema.safeParse(req.query);
  if (!validation.success) {
    return res.status(422).json({ success: false, message: 'Validation failed', errors: validation.error.format(), requestId: req.id });
  }

  const { days } = validation.data;
  const scope = getScopeFilter(req);
  const from = daysAgo(days);

    const where = { ...scope, createdAt: { gte: from } };

    const [byStatus, byPaymentType] = await Promise.all([
      prisma.booking.groupBy({ by: ['status'],      where, _count: { id: true } }),
      prisma.booking.groupBy({ by: ['paymentType'], where, _count: { id: true } }),
    ]);

    res.status(200).json({
      success: true,
      data: {
        byStatus:      byStatus.map(r => ({ label: r.status, count: r._count.id })),
        byPaymentType: byPaymentType.map(r => ({ label: r.paymentType, count: r._count.id })),
      },
      requestId: req.id
    });
});

// ─── GET /api/v1/analytics/top-properties ─────────────────────────────────────
export const getTopProperties = asyncHandler(async (req, res) => {
    const validation = analyticsQuerySchema.safeParse(req.query);
    const { days } = validation.success ? validation.data : { days: 30 };

    const scope = getScopeFilter(req);
    const from = daysAgo(days);

    // Group by hotelId and sum totalAmount
    const results = await prisma.booking.groupBy({
      by:      ['hotelId'],
      where:   { 
        ...scope, 
        status: { in: ['CONFIRMED', 'COMPLETED'] },
        createdAt: { gte: from }
      },
      _sum:    { totalAmount: true },
      _count:  { id: true },
      orderBy: { _sum: { totalAmount: 'desc' } },
      take:    5,
    });

    const hotelIds = results.map(r => r.hotelId);
    const hotels   = await prisma.hotel.findMany({
      where:  { id: { in: hotelIds } },
      select: { id: true, name: true, city: true },
    });

    const data = results.map(r => {
      const h = hotels.find(h => h.id === r.hotelId);
      return {
        id:      r.hotelId,
        name:    h?.name || 'Unknown',
        city:    h?.city || 'N/A',
        revenue: r._sum.totalAmount,
        bookings: r._count.id,
      };
    });

    res.status(200).json({ success: true, data, requestId: req.id });
});

// ─── GET /api/v1/analytics/funnel ─────────────────────────────────────────────
export const getFunnelAnalytics = asyncHandler(async (req, res) => {
    const validation = analyticsQuerySchema.safeParse(req.query);
    const { days } = validation.success ? validation.data : { days: 30 };

    const scope = getScopeFilter(req); // Need to apply this effectively for funnel if required, for now mostly global Admin
    const from = daysAgo(days);

    // 1. Total Searches
    const searches = await prisma.analyticsEvent.count({
      where: { eventType: { in: ['SEARCH_STARTED', 'DESTINATION_SELECTED'] }, createdAt: { gte: from } }
    });

    // 2. Hotel Views
    const hotelViews = await prisma.analyticsEvent.count({
      where: { eventType: 'HOTEL_VIEWED', createdAt: { gte: from } }
    });

    // 3. Total Bookings
    const bookings = await prisma.booking.count({
      where: { status: { in: ['CONFIRMED', 'COMPLETED'] }, createdAt: { gte: from } }
    });

    // Assuming a 30% sampling rate for searches, we adjust the reported search volume back up
    const estimatedSearches = Math.round(searches / 0.3);

    const ctr = estimatedSearches > 0 ? ((hotelViews / estimatedSearches) * 100).toFixed(1) : 0;
    const conversionRate = hotelViews > 0 ? ((bookings / hotelViews) * 100).toFixed(1) : 0;

    res.status(200).json({
      success: true,
      data: {
        searches: estimatedSearches,
        hotelViews,
        bookings,
        conversionRate: parseFloat(conversionRate),
        ctr: parseFloat(ctr)
      },
      requestId: req.id
    });
});

import prisma from '../config/db.js';
import bcrypt from 'bcryptjs';
import jwt from 'jsonwebtoken';
import { asyncHandler } from '../middleware/asyncHandler.js';
import systemCache from '../utils/systemCache.js';
import { z } from 'zod';
import eventBus from '../events/eventBus.js';
import { createOTP, verifyOTP } from '../services/otpService.js';
import { trackOtpAbuse } from '../services/fraudService.js';

// --- ZOD SCHEMAS ---

const signupSchema = z.object({
  name: z.string().min(2, 'Name must be at least 2 characters'),
  email: z.string().email('Invalid email address'),
  password: z.string().min(6, 'Password must be at least 6 characters'),
  role: z.enum(['CUSTOMER', 'OWNER']).optional().default('CUSTOMER')
});

const loginSchema = z.object({
  email: z.string().email('Invalid email address'),
  password: z.string().min(1, 'Password is required')
});

const signToken = (id, role, hotelId, tokenVersion) => {
  return jwt.sign({ id, role, hotelId, tokenVersion }, process.env.JWT_SECRET, {
    expiresIn: process.env.JWT_EXPIRES_IN || '7d',
  });
};

/**
 * @desc    Register a new user
 */
export const signup = asyncHandler(async (req, res) => {
  const validation = signupSchema.safeParse(req.body);
  if (!validation.success) {
    return res.status(422).json({ 
      success: false, 
      message: 'Validation failed', 
      errors: validation.error.format(), 
      requestId: req.id 
    });
  }

  const { name, email, password, role } = validation.data;

  const existingUser = await prisma.user.findUnique({ where: { email } });
  if (existingUser) {
    return res.status(400).json({ success: false, message: 'Email already in use' });
  }

  const salt = await bcrypt.genSalt(10);
  const hashedPassword = await bcrypt.hash(password, salt);

  const newUser = await prisma.user.create({
    data: {
      name,
      email,
      password: hashedPassword,
      role: role === 'OWNER' ? 'OWNER' : 'CUSTOMER',
      lastLogin: new Date(),
      lastActiveAt: new Date()
    }
  });

  const token = signToken(newUser.id, newUser.role, null, newUser.tokenVersion);

  // Async Session Merge
  const sessionId = req.headers['x-session-id'];
  if (sessionId) {
    setImmediate(() => mergeAnonymousSession(sessionId, newUser.id));
  }

  res.status(201).json({
    success: true,
    token,
    requestId: req.id,
    data: { 
      user: { id: newUser.id, name: newUser.name, email: newUser.email, role: newUser.role } 
    }
  });
});

/**
 * @desc    Login user
 */
export const login = asyncHandler(async (req, res) => {
  const validation = loginSchema.safeParse(req.body);
  if (!validation.success) {
    return res.status(422).json({ 
      success: false, 
      message: 'Validation failed', 
      errors: validation.error.format(), 
      requestId: req.id 
    });
  }

  const { email, password } = validation.data;

  const user = await prisma.user.findUnique({ where: { email } });

  if (!user || !(await bcrypt.compare(password, user.password))) {
    // 1. Update system stats
    systemCache.increment('failedLogins');

    // 2. Security Log: Failed Login
    await prisma.securityLog.create({
      data: {
        type: 'FAILED_LOGIN',
        userId: user?.id || null,
        ip: req.ip,
        userAgent: req.headers['user-agent'],
        requestId: req.id,
        details: { email }
      }
    }).catch(err => console.error('Failed to create security log:', err));

    // 3. Audit Log
    await prisma.auditLog.create({
      data: {
        action: 'FAILED_LOGIN',
        entityType: 'USER',
        entityId: user?.id || 'UNKNOWN',
        userId: user?.id || 'ANONYMOUS',
        details: { email, ip: req.ip }
      }
    });

    return res.status(401).json({ success: false, message: 'Invalid credentials', requestId: req.id });
  }

  if (user.status === 'BLOCKED') {
    return res.status(403).json({ success: false, message: 'Account blocked', requestId: req.id });
  }

  // Update last login & last active
  const updatedUser = await prisma.user.update({
    where: { id: user.id },
    data: { 
      lastLogin: new Date(),
      lastActiveAt: new Date()
    }
  });

  // Fetch hotelId if user is an OWNER or MANAGER
  let hotelId = null;
  if (['OWNER', 'MANAGER'].includes(user.role)) {
    const primaryHotel = await prisma.hotel.findFirst({
      where: { ownerId: user.id },
      select: { id: true }
    });
    hotelId = primaryHotel?.id || null;
  }

  const token = signToken(user.id, user.role, hotelId, user.tokenVersion);

  // Async Session Merge
  const sessionId = req.headers['x-session-id'];
  if (sessionId) {
    setImmediate(() => mergeAnonymousSession(sessionId, user.id));
  }

  res.status(200).json({
    success: true,
    token,
    requestId: req.id,
    data: { 
      user: { id: user.id, name: user.name, email: user.email, role: user.role, hotelId } 
    }
  });
});

/**
 * @desc    Send Email OTP
 */
export const sendOtp = asyncHandler(async (req, res) => {
  const schema = z.object({ email: z.string().email() });
  const validation = schema.safeParse(req.body);

  if (!validation.success) {
    return res.status(422).json({ success: false, message: 'Invalid email address' });
  }

  const { email } = validation.data;
  const ipAddress = req.ip;
  const userAgent = req.headers['user-agent'];

  try {
    await createOTP(email, ipAddress, userAgent);

    // Audit & Security Logs
    await prisma.securityLog.create({
      data: {
        type: 'OTP_SENT',
        ip: ipAddress,
        userAgent,
        requestId: req.id,
        details: { 
          email, 
          action: 'SEND_OTP',
          deviceType: userAgent?.includes('Mobile') ? 'Mobile' : 'Desktop',
          status: 'SUCCESS'
        }
      }
    });

    eventBus.emitEvent('OTP_SENT', { email, ipAddress, timestamp: new Date() });

    res.status(200).json({ success: true, message: 'OTP sent successfully' });
  } catch (error) {
    if (error.message.includes('Too many OTP requests')) {
      eventBus.emitEvent('OTP_RATE_LIMITED', { email, ipAddress });
      await prisma.securityLog.create({
        data: {
          type: 'OTP_RATE_LIMITED',
          ip: ipAddress,
          userAgent,
          requestId: req.id,
          details: { 
            email,
            action: 'SEND_OTP',
            deviceType: userAgent?.includes('Mobile') ? 'Mobile' : 'Desktop',
            status: 'RATE_LIMITED'
          }
        }
      });
      await trackOtpAbuse(email, ipAddress);
      return res.status(429).json({ success: false, message: error.message });
    }
    throw error;
  }
});

/**
 * @desc    Verify Email OTP
 */
export const verifyOtp = asyncHandler(async (req, res) => {
  const schema = z.object({ 
    email: z.string().email(),
    otp: z.string().length(6)
  });

  const validation = schema.safeParse(req.body);
  if (!validation.success) {
    return res.status(422).json({ success: false, message: 'Invalid email or OTP format' });
  }

  const { email, otp } = validation.data;
  const ipAddress = req.ip;
  const userAgent = req.headers['user-agent'];

  try {
    await verifyOTP(email, otp);

    eventBus.emitEvent('OTP_VERIFIED', { email, ipAddress, timestamp: new Date() });

    await prisma.securityLog.create({
      data: {
        type: 'OTP_VERIFIED',
        ip: ipAddress,
        userAgent,
        requestId: req.id,
        details: { 
          email,
          action: 'VERIFY_OTP',
          deviceType: userAgent?.includes('Mobile') ? 'Mobile' : 'Desktop',
          status: 'SUCCESS'
        }
      }
    });

    res.status(200).json({ success: true, message: 'OTP verified successfully' });
  } catch (error) {
    eventBus.emitEvent('OTP_FAILED', { email, ipAddress, reason: error.message });

    await prisma.securityLog.create({
      data: {
        type: 'OTP_FAILED',
        ip: ipAddress,
        userAgent,
        requestId: req.id,
        details: { 
          email, 
          action: 'VERIFY_OTP',
          deviceType: userAgent?.includes('Mobile') ? 'Mobile' : 'Desktop',
          status: 'FAILED',
          reason: error.message 
        }
      }
    });

    await trackOtpAbuse(email, ipAddress);

    let statusCode = 400;
    if (error.message.includes('expired')) statusCode = 410;
    else if (error.message.includes('attempts exceeded')) statusCode = 429;

    res.status(statusCode).json({ success: false, message: error.message });
  }
});

