export const detachImageFromRoom = asyncHandler(async (req, res) => {
  const { roomTypeId, imageId } = req.params;

  await prisma.roomTypeImage.deleteMany({
    where: { roomTypeId, imageId }
  });

  res.status(200).json({ success: true, message: 'Image detached from room' });
});

export const setRoomPrimaryImage = asyncHandler(async (req, res) => {
  const { roomTypeId, imageId } = req.params;

  await prisma.$transaction([
    prisma.roomTypeImage.updateMany({
      where: { roomTypeId },
      data: { isPrimary: false }
    }),
    prisma.roomTypeImage.update({
      where: { roomTypeId_imageId: { roomTypeId, imageId } },
      data: { isPrimary: true }
    })
  ]);

  res.status(200).json({ success: true, message: 'Primary image set' });
});

import prisma from '../config/db.js';
import { asyncHandler } from '../middleware/asyncHandler.js';
import { z } from 'zod';

// --- ZOD SCHEMAS ---

const roomTypeSchema = z.object({
  name: z.string().min(2, 'Name is required'),
  code: z.string().min(2, 'Room code is required'),
  description: z.string().optional().default(''),
  maxOccupancy: z.number().int().min(1, 'Max occupancy must be at least 1'),
  baseOccupancy: z.number().int().optional().nullable(),
  totalRooms: z.number().int().min(1, 'Total rooms must be at least 1'),
  hotelId: z.string().uuid('Invalid hotel ID'),
  amenities: z.array(z.string()).optional().default([]),
  bedType: z.string().optional().default('King'),
  roomSize: z.string().optional(),
  viewType: z.string().optional(),
  isActive: z.boolean().optional().default(true),
  extraBedAllowed: z.boolean().optional().default(false),
  maxExtraBeds: z.number().int().optional().default(0),
  imageIds: z.array(z.string().uuid()).optional(),
  primaryImageId: z.string().uuid().optional(),
  basePrice: z.number().optional(),
  mealPlan: z.string().optional(),
}).strict();

const roomTypeUpdateSchema = roomTypeSchema.partial();

// --- HELPERS ---

const normalizeRoomPayload = (data) => {
  const { maxOccupancy, totalRooms, imageIds, primaryImageId, basePrice, mealPlan, ...rest } = data;

  return {
    prismaData: {
      ...rest,
      capacity: maxOccupancy,
      totalInventory: totalRooms,
    },
    basePrice,
    mealPlan
  };
};

export const createRoomType = asyncHandler(async (req, res) => {
  const validation = roomTypeSchema.safeParse(req.body);
  if (!validation.success) {
    return res.status(422).json({ 
      success: false, 
      message: 'Validation failed', 
      errors: validation.error.flatten(), 
      requestId: req.id 
    });
  }

  const normalized = normalizeRoomPayload(validation.data);
  const { hotelId, code } = normalized.prismaData;

  const hotel = await prisma.hotel.findUnique({ where: { id: hotelId } });
  if (!hotel || hotel.isDeleted) return res.status(404).json({ success: false, message: 'Hotel not found', requestId: req.id });

  if (req.user.role === 'OWNER' && hotel.ownerId !== req.user.id) {
    return res.status(403).json({ success: false, message: 'Forbidden', requestId: req.id });
  }

  const roomType = await prisma.$transaction(async (tx) => {
    const room = await tx.roomType.create({
      data: normalized.prismaData
    });

    // Create Default Rate Plan (Clean Default)
    const ratePlan = await tx.ratePlan.create({
      data: {
        name: 'Standard Rate Plan',
        mealPlan: normalized.mealPlan || 'NONE',
        basePrice: normalized.basePrice || 0,
        extraAdultPrice: 0,
        extraChildPrice: 0,
        roomTypeId: room.id,
        isActive: true,
        isConfigured: false,
      }
    });

    // Seed 60 days of inventory
    const startDate = new Date();
    startDate.setHours(0, 0, 0, 0);
    const inventoryData = [];

    for (let i = 0; i < 60; i++) {
      const date = new Date(startDate);
      date.setDate(startDate.getDate() + i);
      inventoryData.push({
        roomTypeId: room.id,
        date,
        totalRooms: room.totalInventory,
        availableRooms: room.totalInventory,
      });
    }

    await tx.inventory.createMany({ 
      data: inventoryData,
      skipDuplicates: true 
    });

    await tx.auditLog.create({
      data: {
        action: 'CREATE_ROOM_TYPE',
        entityType: 'ROOM',
        entityId: room.id,
        userId: req.user.id,
        requestId: req.id,
        details: { name: normalized.prismaData.name, hotelId, autoInventoryDays: 60, defaultRatePlanId: ratePlan.id }
      }
    });

    // Link images if provided
    if (validation.data.imageIds && validation.data.imageIds.length > 0) {
      await tx.roomTypeImage.createMany({
        data: validation.data.imageIds.map(imageId => ({
          roomTypeId: room.id,
          imageId,
          isPrimary: imageId === validation.data.primaryImageId
        }))
      });
    }

    return { ...room, ratePlans: [ratePlan] };
  });

  res.status(201).json({ success: true, data: roomType, requestId: req.id });
});

export const updateRoomType = asyncHandler(async (req, res) => {
  const { id } = req.params;

  const existing = await prisma.roomType.findUnique({
    where: { id },
    include: { hotel: true }
  });

  if (!existing || !existing.isActive) {
    return res.status(404).json({ success: false, message: 'Room not found', requestId: req.id });
  }

  if (req.user.role === 'OWNER' && existing.hotel.ownerId !== req.user.id) {
    return res.status(403).json({ success: false, message: 'Forbidden', requestId: req.id });
  }

  const validation = roomTypeUpdateSchema.safeParse(req.body);
  if (!validation.success) {
    return res.status(422).json({ 
      success: false, 
      message: 'Validation failed', 
      errors: validation.error.flatten(), 
      requestId: req.id 
    });
  }

  const normalized = normalizeRoomPayload(validation.data);

  const roomType = await prisma.$transaction(async (tx) => {
    const updated = await tx.roomType.update({
      where: { id },
      data: normalized.prismaData
    });

    // Update Default Rate Plan
    const standardRate = await tx.ratePlan.findFirst({
      where: { roomTypeId: id, name: 'Standard Rate Plan' }
    });

    if (standardRate && (normalized.basePrice !== undefined || normalized.mealPlan !== undefined)) {
      await tx.ratePlan.update({
        where: { id: standardRate.id },
        data: {
          basePrice: normalized.basePrice !== undefined ? normalized.basePrice : standardRate.basePrice,
          mealPlan: normalized.mealPlan !== undefined ? normalized.mealPlan : standardRate.mealPlan
        }
      });
    }

    // Update Occupancy Pricing for Standard Rate Plan
    if (validation.data.occupancyPricing) {
      const standardRate = await tx.ratePlan.findFirst({
        where: { roomTypeId: id, name: 'Standard Rate' }
      });

      if (standardRate) {
        // Clear old ones
        await tx.occupancyPricing.deleteMany({
          where: { ratePlanId: standardRate.id }
        });
        // Add new ones
        await tx.occupancyPricing.createMany({
          data: validation.data.occupancyPricing.map(op => ({
            ...op,
            ratePlanId: standardRate.id
          }))
        });
      }
    }

    // Update Images
    if (validation.data.imageIds) {
      // Clear old links
      await tx.roomTypeImage.deleteMany({ where: { roomTypeId: id } });
      // Create new ones
      if (validation.data.imageIds.length > 0) {
        await tx.roomTypeImage.createMany({
          data: validation.data.imageIds.map(imageId => ({
            roomTypeId: id,
            imageId,
            isPrimary: imageId === validation.data.primaryImageId
          }))
        });
      }
    }

    return updated;
  });

  await prisma.auditLog.create({
    data: {
      action: 'UPDATE_ROOM',
      entityType: 'ROOM',
      entityId: id,
      userId: req.user.id,
      requestId: req.id,
      details: { changed: Object.keys(req.body) }
    }
  });

  res.status(200).json({ success: true, data: roomType, requestId: req.id });
});

export const deleteRoomType = asyncHandler(async (req, res) => {
  const { id } = req.params;
  const existing = await prisma.roomType.findUnique({
    where: { id },
    include: { hotel: true }
  });

  if (!existing) return res.status(404).json({ success: false, message: 'Room not found', requestId: req.id });
  if (req.user.role === 'OWNER' && existing.hotel.ownerId !== req.user.id) {
    return res.status(403).json({ success: false, message: 'Forbidden', requestId: req.id });
  }

  await prisma.roomType.update({
    where: { id },
    data: { isActive: false }
  });

  await prisma.auditLog.create({
    data: { action: 'DELETE_ROOM', entityType: 'ROOM', entityId: id, userId: req.user.id, requestId: req.id }
  });

  res.status(200).json({ success: true, message: 'Room type deleted', requestId: req.id });
});

export const getRoomTypes = asyncHandler(async (req, res) => {
  const { hotelId, propertyId } = req.query;
  const finalId = hotelId || propertyId;

  if (!finalId) return res.status(400).json({ success: false, message: 'Hotel ID required', requestId: req.id });

  const hotel = await prisma.hotel.findUnique({ where: { id: finalId } });
  if (!hotel || hotel.isDeleted) return res.status(404).json({ success: false, message: 'Hotel not found', requestId: req.id });

  if (req.user.role === 'OWNER' && hotel.ownerId !== req.user.id) {
    return res.status(403).json({ success: false, message: 'Forbidden', requestId: req.id });
  }

  const roomTypes = await prisma.roomType.findMany({ 
    where: { hotelId: finalId, isActive: true },
    include: { 
      ratePlans: { 
        where: { isActive: true },
        include: { occupancyPricing: { orderBy: { occupancy: 'asc' } } }
      },
      images: { 
        include: { image: true } 
      }
    },
    orderBy: { name: 'asc' }
  });

  res.status(200).json({ success: true, data: roomTypes, requestId: req.id });
});

import prisma from '../../config/db.js';
import channelManagerService from '../../services/channel/channelManagerService.js';

export const channelWebhookController = {
  /**
   * Handle incoming ARI (Availability, Rate, Inventory) updates
   */
  handleARIUpdate: async (req, res) => {
    try {
      const { provider } = req.params; // e.g., staah
      const payload = req.body;

      // 1. Authenticate (HMAC / API Key)
      // verifySignature(req);

      // 2. Identify Hotel via mapping
      // In a real system, the payload contains externalHotelId
      const externalHotelId = payload.hotel_id;
      const hotelMapping = await prisma.channelMapping.findFirst({
        where: { externalHotelId }
      });

      if (!hotelMapping) {
        return res.status(404).json({ success: false, message: 'Hotel mapping not found' });
      }

      const hotelId = hotelMapping.hotelId;

      // 3. Process updates based on provider logic
      const { adapter } = await channelManagerService.getAdapter(hotelId);
      const unifiedUpdate = await adapter.handleWebhook(payload);

      // 4. Update Zivo DB (Inventory & potentially base rates)
      // This keeps Zivo in sync with the Channel Manager source of truth
      for (const update of unifiedUpdate.updates) {
        // Map externalRoomId back to roomTypeId
        const roomMapping = await prisma.channelMapping.findFirst({
          where: { hotelId, externalRoomId: update.roomTypeId }
        });

        if (roomMapping) {
          await prisma.inventory.upsert({
            where: {
              roomTypeId_date: {
                roomTypeId: roomMapping.roomTypeId,
                date: new Date(update.date)
              }
            },
            update: { available: update.available },
            create: {
              hotelId,
              roomTypeId: roomMapping.roomTypeId,
              date: new Date(update.date),
              available: update.available,
              total: update.available // Assuming CM sends available physical rooms
            }
          });
        }
      }

      return res.status(200).json({ success: true });
    } catch (error) {
      console.error('[Webhook] ARI Update Error:', error);
      return res.status(500).json({ success: false, error: error.message });
    }
  }
};

export default channelWebhookController;

/**
 * Dynamic Pricing Domain (Pure Business Logic)
 * 
 * Rules:
 * - NO database queries (Prisma)
 * - NO external side-effects
 * - Pure Input -> Output
 */

/**
 * Exponential proximity decay for holiday multipliers.
 * The effect peaks on the holiday day and ramps up/down:
 *   multiplier(t) = base * exp(-|daysToHoliday| / 2)
 * 
 * This means:
 *   - 0 days away: 100% of multiplier
 *   - 1 day away: 60.7%
 *   - 2 days away: 36.8%
 *   - 4 days away: 13.5%
 */
function applyHolidayDecay(baseMultiplier, daysAway) {
  return baseMultiplier * Math.exp(-Math.abs(daysAway) / 2);
}

export const dynamicPricingDomain = {

  /**
   * Calculates the final dynamic price per night
   * 
   * @param {Object} context
   * @param {Number} context.basePrice - Original base price for the night
   * @param {Date}   context.date - The specific date for this price
   * @param {Number} context.demandScore - Normalized demand score (0 to 1), default 0.5
   * @param {Number} context.availableRooms - Remaining inventory
   * @param {String} context.userSegment - 'BUDGET' | 'PREMIUM' | 'RETURNING' | 'STANDARD'
   * @param {Object} context.experimentModifiers - Experiment variants active for this user
   * @param {Object} context.pricingRules - Optional manual overrides or dynamic rules
   * @param {Number} context.previousPrice - From PricingState.lastAppliedPrice (for rate-change cap)
   * @param {Array}  context.holidays - From HolidayCalendar (active entries for date range)
   * @returns {Object} breakdown with finalPrice
   */
  calculateDynamicPrice: (context) => {
    const { 
      basePrice, 
      date, 
      demandScore = 0.5, 
      availableRooms = 999, 
      userSegment = 'STANDARD',
      experimentModifiers = {},
      pricingRules = {},
      previousPrice = null,
      holidays = [],
      aiPrediction = null      // From Phase 7.5 pricingModelService
    } = context;

    let price = basePrice;
    const breakdown = {
      basePrice,
      demandAdjustment: 0,
      inventoryAdjustment: 0,
      timeAdjustment: 0,
      segmentAdjustment: 0,
      experimentAdjustment: 0,
      aiAdjustment: 0,         // New for Phase 7.5
      gstFloorApplied: false,
      finalPrice: basePrice
    };

    // 1. Demand Adjustment
    // Experiment can override the elasticity weight (for pricing sensitivity A/B tests)
    const demandWeight = experimentModifiers.pricing_demand_weight ?? 0.3;
    const demandAdjPercent = (demandScore - 0.5) * demandWeight;
    breakdown.demandAdjustment = Math.round(basePrice * demandAdjPercent);

    // 2. Inventory Pressure
    let inventoryAdjPercent = 0;
    if (availableRooms <= 2) inventoryAdjPercent = 0.20;
    else if (availableRooms <= 5) inventoryAdjPercent = 0.10;
    breakdown.inventoryAdjustment = Math.round(basePrice * inventoryAdjPercent);

    // 3. Time-based Pricing with Holiday Proximity Decay
    const dateObj = new Date(date);
    const dayOfWeek = dateObj.getDay();
    const dateStr = dateObj.toISOString().split('T')[0];
    const dateMs = dateObj.getTime();

    // Base: weekend uplift
    let timeAdjPercent = (dayOfWeek === 5 || dayOfWeek === 6) ? 0.10 : 0;

    // Holiday proximity: find the nearest active holiday and apply decayed multiplier
    // Multiple holidays within range are all considered; highest effective multiplier wins
    let bestHolidayEffect = 0;
    for (const h of holidays) {
      const holidayMs = new Date(h.date).getTime();
      const daysAway = (dateMs - holidayMs) / (1000 * 60 * 60 * 24); // negative = before holiday

      // Hard cap holiday multiplier at 40% (+0.40) to prevent extreme spikes
      const cappedBaseMultiplier = Math.min(h.multiplier, 0.4);
      const decayedMultiplier = applyHolidayDecay(cappedBaseMultiplier, daysAway);

      if (decayedMultiplier > bestHolidayEffect) {
        bestHolidayEffect = decayedMultiplier;
        breakdown.holidayApplied = h.name;
        breakdown.holidayDecayedMultiplier = parseFloat(decayedMultiplier.toFixed(4));
      }
    }

    // Holiday effect overrides weekend if stronger (on the holiday day itself it dominates)
    if (bestHolidayEffect > timeAdjPercent) {
      timeAdjPercent = bestHolidayEffect;
    }

    breakdown.timeAdjustment = Math.round(basePrice * timeAdjPercent);

    // 4. User Segment Pricing (invisible to user — kept within ±5%)
    let segmentAdjPercent = 0;
    if (userSegment === 'BUDGET') segmentAdjPercent = -0.05;
    else if (userSegment === 'PREMIUM') segmentAdjPercent = 0.05;
    else if (userSegment === 'RETURNING') segmentAdjPercent = 0.03;
    breakdown.segmentAdjustment = Math.round(basePrice * segmentAdjPercent);

    // 5. AI Pricing Engine (Phase 7.5 Override)
    // If AI is active, it takes over the demand-elasticity and segment-optimization logic
    if (aiPrediction && aiPrediction.multiplier !== undefined) {
      const aiTargetPrice = basePrice * aiPrediction.multiplier;
      breakdown.aiAdjustment = Math.round(aiTargetPrice - basePrice);

      // Zero out redundant rule-based adjustments to avoid double-charging
      breakdown.demandAdjustment = 0;
      breakdown.segmentAdjustment = 0;
      breakdown.aiModel = aiPrediction.modelVersion;
      breakdown.aiSource = aiPrediction.source;
    }

    // 6. Experiment Integration (direct price elasticity testing)
    let experimentAdjPercent = 0;
    if (experimentModifiers.pricing_adjustment) {
      experimentAdjPercent = experimentModifiers.pricing_adjustment;
    }
    breakdown.experimentAdjustment = Math.round(basePrice * experimentAdjPercent);

    // 7. Calculate Unclamped Final Price
    price = basePrice +
            breakdown.demandAdjustment +
            breakdown.inventoryAdjustment +
            breakdown.timeAdjustment +
            breakdown.segmentAdjustment +
            breakdown.experimentAdjustment +
            breakdown.aiAdjustment;

    // 7. Absolute Safety Clamp (0.7x to 1.5x of base — hard floor/ceiling)
    const minPriceAbsolute = basePrice * 0.7;
    const maxPriceAbsolute = basePrice * 1.5;
    price = Math.min(Math.max(price, minPriceAbsolute), maxPriceAbsolute);

    // 8. Rate-Change Stability Clamp (±10% per booking session vs last applied price)
    if (previousPrice && previousPrice > 0) {
      const minPriceRelative = previousPrice * 0.9;
      const maxPriceRelative = previousPrice * 1.1;
      price = Math.min(Math.max(price, minPriceRelative), maxPriceRelative);
    }

    breakdown.finalPrice = Math.round(price);
    return breakdown;
  }
};

export default dynamicPricingDomain;

/**
 * Ranking Domain (Pure Logic)
 * 
 * Rules:
 * - NO database queries
 * - Pure mathematical scoring algorithm
 * - Deterministic outputs
 */
export const rankingDomain = {

  /**
   * Calculates the ranking score for a hotel based on multiple normalized vectors
   * 
   * @param {Object} hotel 
   * @param {Number} minPrice - The lowest price found in the current search result set
   * @returns {Number} score
   */
  calculateScore: (hotel, minPrice) => {
    // 1. Extract raw values with fallbacks
    const rating = hotel.rating || 0;
    const commission = hotel.commission || 15; // default OTA commission
    const totalRooms = hotel.totalRooms || 1;
    const availableRooms = hotel.availableRooms || 0;
    const price = hotel.price || minPrice;

    // 2. Normalize inputs to 0-1 range
    const ratingScore = rating / 5;

    // Commission score: Cap max commission at 30% for normalization
    const maxExpectedCommission = 30;
    const commissionScore = Math.min(commission / maxExpectedCommission, 1);

    // Availability score
    const availabilityScore = totalRooms > 0 ? Math.min(availableRooms / totalRooms, 1) : 0;

    // Price competitiveness: Min price gets 1.0, higher prices drop down towards 0
    const priceCompetitiveness = hotel.price > 0 && minPrice > 0 ? minPrice / hotel.price : 0;

    // Conversion Proxy: Phase 3 placeholder (1.0)
    const conversionProxy = 1.0;

    // 3. Apply Weighting Formula
    const score = 
        (ratingScore * 0.4) 
      + (priceCompetitiveness * 0.3) 
      + (availabilityScore * 0.1) 
      + (commissionScore * 0.1) 
      + (conversionProxy * 0.1);

    // Round to 4 decimal places
    return Math.round(score * 10000) / 10000;
  }

};

export default rankingDomain;

import prisma from '../config/db.js';
