let browserInstance = null;

/**
 * Singleton Browser instance for Puppeteer
 */
const getBrowser = async () => {
  if (!browserInstance || !browserInstance.isConnected()) {
    browserInstance = await puppeteer.launch({
      headless: 'new',
      args: ['--no-sandbox', '--disable-setuid-sandbox']
    });
  }
  return browserInstance;
};

process.on('SIGINT', async () => {
  if (browserInstance) {
    await browserInstance.close();
  }
  process.exit(0);
});

export const invoiceService = {

  /**
   * Generates a unique, atomic invoice number
   */
  generateInvoiceNumber: async (tx) => {
    const currentYear = new Date().getFullYear();

    // Ensure row exists safely outside the hot path locking if possible, or just standard upsert
    await tx.invoiceSequence.upsert({
      where: { year: currentYear },
      update: {},
      create: { year: currentYear, counter: 0 }
    });

    // Atomic increment with lock
    const sequences = await tx.$queryRaw`
      UPDATE "InvoiceSequence"
      SET "counter" = "counter" + 1
      WHERE "year" = ${currentYear}
      RETURNING "counter";
    `;

    const counter = sequences[0].counter;
    const paddedCounter = String(counter).padStart(6, '0');
    return `ZIV/${currentYear}/${paddedCounter}`;
  },

  /**
   * Core generation logic
   */
  generateInvoice: async (bookingId) => {
    // 1. Idempotency Check
    const existingInvoice = await prisma.invoice.findUnique({
      where: { bookingId }
    });
    if (existingInvoice) return existingInvoice;

    // 2. Fetch required snapshots and relations
    const booking = await prisma.booking.findUnique({
      where: { id: bookingId },
      include: { hotel: true, user: true }
    });

    if (!booking) throw new Error('Booking not found');

    // 3. Save DB Record inside transaction (includes atomic numbering and audit)
    const invoice = await prisma.$transaction(async (tx) => {
      // Atomic Number Generation
      const invoiceRef = await invoiceService.generateInvoiceNumber(tx);

      // Generate HTML using Pure Domain
      const htmlContent = invoiceDomain.generateHTML({
        booking,
        hotel: booking.hotel,
        invoiceRef,
        issueDate: new Date()
      });

      // Generate PDF using Puppeteer
      const browser = await getBrowser();
      const page = await browser.newPage();

      let pdfUrl = '';

      try {
        await page.setContent(htmlContent, { waitUntil: 'networkidle0' });

        const safeInvoiceRef = invoiceRef.replace(/\//g, '_');
        const invoicesDir = path.join(process.cwd(), 'public', 'invoices', booking.hotelId, bookingId);
        await fs.mkdir(invoicesDir, { recursive: true });

        const fileName = `${safeInvoiceRef}.pdf`;
        const filePath = path.join(invoicesDir, fileName);
        const tmpPath = `${filePath}.tmp`;

        // Atomic file write
        await page.pdf({ path: tmpPath, format: 'A4', printBackground: true });
        await fs.rename(tmpPath, filePath); // atomic swap

        pdfUrl = `/invoices/${booking.hotelId}/${bookingId}/${fileName}`;
      } finally {
        await page.close();
      }

      const created = await tx.invoice.create({
        data: {
          invoiceRef,
          bookingId,
          pdfUrl,
          status: 'GENERATED'
        }
      });

      // Audit Log
      await tx.auditLog.create({
        data: {
          action: 'INVOICE_GENERATED',
          entityType: 'INVOICE',
          entityId: created.id,
          userId: 'SYSTEM',
          details: { bookingId, invoiceRef, pdfUrl }
        }
      });

      return created;
    });

    return invoice;
  },

  /**
   * Regenerates an existing invoice PDF without creating a new sequence
   */
  regenerateInvoice: async (bookingId) => {
    return await prisma.$transaction(async (tx) => {
      // Row lock to prevent concurrent regenerations
      const lockedInvoices = await tx.$queryRaw`
        SELECT id, "invoiceRef", "pdfUrl" FROM "Invoice" 
        WHERE "bookingId" = ${bookingId} FOR UPDATE
      `;

      if (!lockedInvoices || lockedInvoices.length === 0) {
        throw new Error('Invoice not found for this booking. Cannot regenerate.');
      }
      const existingInvoice = lockedInvoices[0];

      const booking = await tx.booking.findUnique({
        where: { id: bookingId },
        include: { hotel: true, user: true }
      });

      const htmlContent = invoiceDomain.generateHTML({
        booking,
        hotel: booking.hotel,
        invoiceRef: existingInvoice.invoiceRef,
        issueDate: new Date()
      });

      const browser = await getBrowser();
      const page = await browser.newPage();

      let newPdfUrl = '';

      try {
        await page.setContent(htmlContent, { waitUntil: 'networkidle0' });

        const safeInvoiceRef = existingInvoice.invoiceRef.replace(/\//g, '_');
        const invoicesDir = path.join(process.cwd(), 'public', 'invoices', booking.hotelId, bookingId);
        await fs.mkdir(invoicesDir, { recursive: true });

        const fileName = `${safeInvoiceRef}.pdf`;
        const filePath = path.join(invoicesDir, fileName);
        const tmpPath = `${filePath}.tmp`;

        // Atomic file write
        await page.pdf({ path: tmpPath, format: 'A4', printBackground: true });
        await fs.rename(tmpPath, filePath); // atomic swap

        newPdfUrl = `/invoices/${booking.hotelId}/${bookingId}/${fileName}`;
      } finally {
        await page.close();
      }

      const updated = await tx.invoice.update({
        where: { id: existingInvoice.id },
        data: { pdfUrl: newPdfUrl }
      });

      await tx.auditLog.create({
        data: {
          action: 'INVOICE_REGENERATED',
          entityType: 'INVOICE',
          entityId: existingInvoice.id,
          userId: 'SYSTEM',
          details: { bookingId, invoiceRef: existingInvoice.invoiceRef }
        }
      });

      return updated;
    });
  }
};

export default invoiceService;

import prisma from '../config/db.js';
import bcrypt from 'bcryptjs';
import { sendOTPEmail } from './emailService.js';
import crypto from 'crypto';

const OTP_EXPIRY_MINUTES = parseInt(process.env.OTP_EXPIRY_MINUTES || '10', 10);

/**
 * Generate a 6-digit numeric OTP
 */
export const generateOTP = () => {
  return Math.floor(100000 + Math.random() * 900000).toString();
};

/**
 * Check if the user is rate limited for sending OTPs
 * Rule: Max 3 requests per email per 15 mins
 */
export const checkRateLimits = async (email) => {
  const fifteenMinsAgo = new Date(Date.now() - 15 * 60 * 1000);

  const recentOtps = await prisma.emailOTP.count({
    where: {
      email,
      createdAt: { gte: fifteenMinsAgo }
    }
  });

  if (recentOtps >= 20) {
    throw new Error('Too many OTP requests. Please try again in 15 minutes.');
  }
};

/**
 * Invalidate previous active OTPs
 */
export const invalidateOTP = async (email) => {
  await prisma.emailOTP.updateMany({
    where: { 
      email, 
      verified: false,
      expiresAt: { gt: new Date() }
    },
    data: { 
      expiresAt: new Date() // Expire them immediately
    }
  });
};

/**
 * Create and send OTP
 */
export const createOTP = async (email, ipAddress, userAgent) => {
  await checkRateLimits(email);
  await invalidateOTP(email);

  const otp = generateOTP();
  const salt = await bcrypt.genSalt(10);
  const otpHash = await bcrypt.hash(otp, salt);

  const expiresAt = new Date(Date.now() + OTP_EXPIRY_MINUTES * 60 * 1000);

  const newOtp = await prisma.emailOTP.create({
    data: {
      email,
      otpHash,
      expiresAt,
      ipAddress,
      userAgent
    }
  });

  await sendOTPEmail(email, otp, OTP_EXPIRY_MINUTES);

  return newOtp;
};

/**
 * Verify OTP
 */
export const verifyOTP = async (email, otp) => {
  // Find the latest active OTP
  const record = await prisma.emailOTP.findFirst({
    where: { email },
    orderBy: { createdAt: 'desc' }
  });

  if (!record) {
    throw new Error('No OTP found for this email.');
  }

  // 5 failed attempts locks OTP verification (for 15 minutes handled by rate limit or just expiry)
  // Actually, we can check attempts
  if (record.attempts >= 5) {
    throw new Error('Maximum verification attempts exceeded. Please request a new OTP.');
  }

  if (record.expiresAt < new Date()) {
    throw new Error('OTP has expired. Please request a new one.');
  }

  if (record.verified) {
    throw new Error('OTP has already been used.');
  }

  // Increment attempt
  await prisma.emailOTP.update({
    where: { id: record.id },
    data: { attempts: record.attempts + 1 }
  });

  const isMatch = await bcrypt.compare(otp, record.otpHash);

  if (!isMatch) {
    throw new Error('Invalid OTP code.');
  }

  // Mark as verified
  await prisma.emailOTP.update({
    where: { id: record.id },
    data: { 
      verified: true,
      verifiedAt: new Date()
    }
  });

  return true;
};

/**
 * ZivoHotels Policy Engine
 * Declarative governance policies for autonomous system coordination.
 */
class PolicyEngine {
  constructor() {
    this.currentVersion = 'v1.2.0';
    this.policies = {
      // FINANCIAL PROTECTION
      PAYOUT_PROTECTION: {
        id: 'POL_FIN_001',
        description: 'Automatic payout freeze on high failure rates',
        condition: (metrics) => metrics.payoutFailures > 5 && metrics.timeWindow === '1h',
        action: 'TRIGGER_SAFE_MODE',
        confidenceThreshold: 0.9,
        priority: 100,
        version: '1.2.0',
        cooldown: 15 * 60 * 1000 // 15 mins
      },

      // RISK PROTECTION
      REFUND_SURGE: {
        id: 'POL_RSK_001',
        description: 'Throttling hotel on refund rate spikes',
        condition: (metrics) => metrics.refundRate > 0.20, // 20%
        action: 'THROTTLE_HOTEL',
        confidenceThreshold: 0.85,
        priority: 80,
        cooldown: 30 * 60 * 1000 // 30 mins
      },

      // SYSTEM INTEGRITY
      LEDGER_DRIFT: {
        id: 'POL_SYS_001',
        description: 'Graduated response to ledger integrity issues',
        condition: (metrics) => metrics.integrityMismatch === true,
        action: 'FINANCIAL_LOCKDOWN',
        confidenceThreshold: 1.0, 
        priority: 1000, // Critical priority
        cooldown: 0 
      }
    };
  }

  /**
   * Arbitrates between multiple matching policies based on priority and confidence.
   */
  arbitrate(matches) {
    if (matches.length === 0) return null;
    return matches.sort((a, b) => b.policy.priority - a.policy.priority)[0];
  }

  /**
   * Safe Policy Rollback
   */
  rollback(policyId, toVersion) {
    console.log(`[PolicyEngine] Rolling back ${policyId} to version ${toVersion}...`);
    // Logic to revert policy definition from persistent storage
  }

  /**
   * Evaluates a set of metrics against registered policies.
   */
  evaluate(policyId, metrics) {
    const policy = this.policies[policyId];
    if (!policy) return { match: false };

    const isMatch = policy.condition(metrics);
    return {
      match: isMatch,
      policy: policy,
      confidence: isMatch ? policy.confidenceThreshold : 0
    };
  }

  /**
   * Returns all policies for a given category.
   */
  getPoliciesByCategory(category) {
