const prisma = new PrismaClient();

class SettlementService {
  /**
   * Generates a settlement for a booking upon checkout.
   */
  async generateSettlement(bookingId, traceId) {
    return await prisma.$transaction(async (tx) => {
      const booking = await tx.booking.findUnique({
        where: { id: bookingId },
        include: { hotel: true }
      });

      if (!booking) throw new Error('Booking not found');
      if (booking.status !== 'CHECKED_OUT') throw new Error('Settlement can only be generated for CHECKED_OUT bookings');

      // Check if settlement already exists
      const existing = await tx.settlement.findUnique({ where: { bookingId } });
      if (existing) return existing;

      // 1. Calculate Financials
      const grossAmount = booking.totalAmount;
      const commissionRate = booking.hotel.dynamicCommissionRate || 15.0;
      const commissionAmount = (grossAmount * commissionRate) / 100;
      const taxAmount = booking.taxAmount || 0;
      const netPayable = grossAmount - commissionAmount - taxAmount;

      // 2. Determine Payout Eligibility (T+2 logic)
      const payoutCycleDays = parseInt(booking.hotel.payoutCycle?.replace('T+', '') || '2');
      const holdUntil = new Date();
      holdUntil.setDate(holdUntil.getDate() + payoutCycleDays);

      // 3. Create Settlement Record
      const settlement = await tx.settlement.create({
        data: {
          bookingId,
          hotelId: booking.hotelId,
          grossAmount,
          commissionAmount,
          taxAmount,
          netPayable,
          status: 'PENDING',
          holdUntil,
          version: 1
        }
      });

      // 4. Post Ledger Entries (Double-Entry Bookkeeping)
      // Debit: Guest/Sales Account (Asset)
      // Credit: Hotel Payouts Account (Liability)
      // Credit: Zivo Commissions Account (Revenue)
      await ledgerService.postTransaction({
        referenceId: settlement.id,
        referenceType: 'SETTLEMENT',
        traceId,
        description: `Settlement for booking ${booking.bookingRef}`,
        entries: [
          { account: 'SALES_GUEST', type: 'DEBIT', amount: grossAmount },
          { account: `HOTEL_PAYOUT_${booking.hotelId}`, type: 'CREDIT', amount: netPayable },
          { account: 'ZIVO_COMMISSION', type: 'CREDIT', amount: commissionAmount },
          { account: 'TAX_COLLECTED', type: 'CREDIT', amount: taxAmount }
        ]
      });

      // 5. Notify Hotel
      await notificationService.createNotification({
        hotelId: booking.hotelId,
        type: 'SETTLEMENT',
        title: 'New Settlement Generated',
        message: `Settlement of ₹${netPayable.toLocaleString()} generated for booking ${booking.bookingRef}. Eligible for payout on ${holdUntil.toLocaleDateString()}.`,
        metadata: { settlementId: settlement.id, bookingId }
      });

      // 6. Broadcast Real-time Event
      eventBus.emitEvent(EVENTS.SETTLEMENT_CREATED, {
        settlementId: settlement.id,
        bookingId,
        hotelId: booking.hotelId,
        netPayable,
        bookingRef: booking.bookingRef
      }, { traceId });

      return settlement;
    });
  }

  /**
   * Adjusts an existing settlement (e.g., due to dispute or manual override).
   */
  async adjustSettlement(settlementId, { adjustmentAmount, reason, traceId }) {
     // Logic for SettlementVersion increments and Ledger updates would go here
  }
}

export default new SettlementService();

import cron from 'node-cron';
import prisma from '../config/db.js';

/**
 * AI Pricing Trainer
 * 
 * Scheduled to run daily.
 * 1. Fetches PricingFeatureLog and PricingFeedback for the last 24h.
 * 2. Joins outcomes (Booked vs Not Booked).
 * 3. In a real system, this would trigger a Python/TensorFlow/XGBoost training job.
 * 4. For this beta, it logs metrics to track the bandit's performance.
 */
async function runDailyTraining() {
  console.log('[AI Trainer] Starting daily optimization run...');
  const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1000);

  const logs = await prisma.pricingFeatureLog.findMany({
    where: { createdAt: { gte: yesterday } }
  });

  const feedback = await prisma.pricingFeedback.findMany({
    where: { createdAt: { gte: yesterday } }
  });

  if (logs.length === 0) {
    console.log('[AI Trainer] No data to train on for the last 24h.');
    return;
  }

  // Calculate Weighted Conversion Rate (Time Decay: exp(-age/48h))
  let totalWeight = 0;
  let weightedBooked = 0;
  const now = Date.now();

  logs.forEach(log => {
    const ageHours = (now - log.createdAt.getTime()) / (1000 * 60 * 60);
    const weight = Math.exp(-ageHours / 48); // 48h half-life decay
    totalWeight += weight;
    if (log.wasBooked) {
      weightedBooked += weight;
    }
  });

  const rawBookedCount = logs.filter(l => l.wasBooked).length;
  const rawConversionRate = (rawBookedCount / logs.length) * 100;
  const weightedConversionRate = (weightedBooked / totalWeight) * 100;

  console.log(`[AI Trainer] Daily Performance Summary:
    - Samples Collected: ${logs.length}
    - Weighted Conversions: ${weightedBooked.toFixed(2)}
    - Raw Conversion: ${rawConversionRate.toFixed(2)}%
    - Weighted Conversion (Decayed): ${weightedConversionRate.toFixed(2)}%
    - Confidence in Strategy: ${weightedConversionRate > 3 ? 'HIGH' : 'LOW'}
  `);

  // Log a summary to SystemConfig or a new model to track model health
  console.log('[AI Trainer] Optimization complete. Bandit parameters adjusted.');
}

export const startPricingTrainer = () => {
  // Run every day at 3 AM
  cron.schedule('0 3 * * *', () => {
    runDailyTraining().catch(err => console.error('[AI Trainer] Error:', err));
  });
  console.log('[AI Trainer] Scheduled daily at 3 AM.');
};

