               <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">{key.replace(/_/g, ' ')}</p>
               <p className="text-sm font-black text-gray-900">{val}</p>
             </div>
           ))}
        </div>
      </div>
    </div>
  );
};

