import React, { useState, useEffect, useRef } from 'react';
import { Calendar as CalendarIcon, ArrowRight } from 'lucide-react';
import { DayPicker } from 'react-day-picker';
import { format, addDays, isBefore, startOfToday } from 'date-fns';
import 'react-day-picker/dist/style.css';
import { track } from '../../utils/analytics';

const DatePickerV2 = ({ checkIn, setCheckIn, checkOut, setCheckOut, error, isOpen, setIsOpen, onFocusNext, isMobile }) => {
  const wrapperRef = useRef(null);

  // Internal state to manage the range
  const [range, setRange] = useState({
    from: checkIn ? new Date(checkIn) : startOfToday(),
    to: checkOut ? new Date(checkOut) : addDays(startOfToday(), 1)
  });

  // Handle outside click
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target)) {
        // Only close if we actually clicked outside. 
        // Don't auto-close immediately if they just opened it.
        setIsOpen(false);
      }
    };
    if (isOpen) {
      document.addEventListener('mousedown', handleClickOutside);
    }
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isOpen, setIsOpen]);

  const handleSelect = (newRange) => {
    setRange(newRange);

    if (newRange?.from) {
      setCheckIn(format(newRange.from, 'yyyy-MM-dd'));
    }

    // Auto-advance if both dates are selected
    if (newRange?.from && newRange?.to) {
      setCheckOut(format(newRange.to, 'yyyy-MM-dd'));
      setIsOpen(false);
      track("DATES_SELECTED", { 
        checkIn: format(newRange.from, 'yyyy-MM-dd'),
        checkOut: format(newRange.to, 'yyyy-MM-dd')
      });
      // Move to Guest selector
      onFocusNext();
    }
  };

  const today = startOfToday();

  // Custom styling for the day picker to match brand
  const cssStyles = `
    .rdp {
      --rdp-cell-size: 40px;
      --rdp-accent-color: #EF4444; /* brand-500 */
      --rdp-background-color: #FEF2F2; /* brand-50 */
      margin: 0;
    }
    .rdp-day_selected, .rdp-day_selected:focus-visible, .rdp-day_selected:hover {
      background-color: var(--rdp-accent-color);
      color: white;
      font-weight: bold;
    }
    .rdp-day_selected:hover {
      background-color: #DC2626; /* brand-600 */
    }
  `;

  const toggleCalendar = (e) => {
    e.stopPropagation();
    setIsOpen(!isOpen);
  };

  return (
    <div className="flex-1 relative group" ref={wrapperRef}>
      <style>{cssStyles}</style>
      <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1 ml-1">Dates</label>

      <div 
        className={`flex items-center border rounded-xl px-4 py-3 bg-white transition-colors cursor-pointer ${isOpen ? 'border-brand-500 ring-2 ring-brand-500/20' : 'border-gray-200 hover:border-brand-500'} ${error ? 'border-red-500 ring-2 ring-red-500/20' : ''}`}
        onClick={toggleCalendar}
      >
        <CalendarIcon className={`mr-3 h-5 w-5 ${error ? 'text-red-500' : (isOpen ? 'text-brand-500' : 'text-gray-400')}`} />

        <div className="flex flex-1 items-center justify-between text-sm font-medium text-gray-800 pointer-events-none">
          <span>{range.from ? format(range.from, 'MMM dd, yyyy') : 'Add Check-in'}</span>
          <ArrowRight className="h-4 w-4 text-gray-300 mx-2" />
          <span>{range.to ? format(range.to, 'MMM dd, yyyy') : 'Add Check-out'}</span>
        </div>
      </div>

      {isOpen && (
        <div className="absolute z-[9999] mt-2 bg-white rounded-xl shadow-2xl border border-gray-100 p-4 animate-fade-in origin-top left-0 md:-left-10 lg:left-0">
          <DayPicker
            mode="range"
            selected={range}
            onSelect={handleSelect}
            numberOfMonths={isMobile ? 1 : 2}
            disabled={{ before: today }}
            pagedNavigation
            showOutsideDays={false}
          />
        </div>
      )}
    </div>
  );
};

export default React.memo(DatePickerV2);

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { MapPin, Search, Navigation, History, Map as MapIcon, Building, AlertCircle } from 'lucide-react';
import { track } from '../../utils/analytics';

const BASE_URL = import.meta.env.VITE_API_URL || '/api/v1';

// Global memory cache for autocomplete
const searchCache = new Map();

const CACHE_TTL = 5 * 60 * 1000; // 5 minutes

const DestinationAutocomplete = ({ destination, setDestination, error, onFocusNext, isMobile }) => {
  const [query, setQuery] = useState(destination?.label || '');
  const [isOpen, setIsOpen] = useState(false);
  const [suggestions, setSuggestions] = useState([]);
  const [popularCities, setPopularCities] = useState([]);
  const [recentSearches, setRecentSearches] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const [fetchError, setFetchError] = useState(false);
  const [focusedIndex, setFocusedIndex] = useState(-1);
  const wrapperRef = useRef(null);

  // Load recent searches and popular cities on mount
  useEffect(() => {
    const saved = localStorage.getItem('zivo_recent_searches');
    if (saved) {
      try {
        setRecentSearches(JSON.parse(saved));
      } catch (e) {
        console.error('Failed to parse recent searches');
      }
    }

    const fetchPopular = async () => {
      try {
        const res = await fetch(`${BASE_URL}/public/search/popular`);
        if (res.ok) {
          const data = await res.json();
          setPopularCities(data);
        }
      } catch (error) {
        console.error('Failed to fetch popular cities', error);
      }
    };
    fetchPopular();
  }, []);

  // Handle outside click
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Smart Search API with Debounce & AbortController
  useEffect(() => {
    if (!query || query.length < 2) {
      setSuggestions([]);
      return;
    }

    // Check Cache
    if (searchCache.has(query)) {
      const { data, timestamp } = searchCache.get(query);
      if (Date.now() - timestamp < CACHE_TTL) {
        setSuggestions(data);
        setFetchError(false);
        return;
      } else {
        searchCache.delete(query);
      }
    }

    const controller = new AbortController();
    setIsLoading(true);
    setFetchError(false);

    const timer = setTimeout(async () => {
      try {
        const res = await fetch(`${BASE_URL}/public/search?q=${encodeURIComponent(query)}`, {
          signal: controller.signal
        });

        if (!res.ok) throw new Error('Network error');

        const data = await res.json();
        searchCache.set(query, { data, timestamp: Date.now() });
        setSuggestions(data);
      } catch (err) {
        if (err.name !== 'AbortError') {
          console.error('Search API Error:', err);
          setFetchError(true);
        }
      } finally {
        setIsLoading(false);
      }
    }, 300); // 300ms debounce

    return () => {
      clearTimeout(timer);
      controller.abort();
    };
  }, [query]);

  const handleSelect = (item) => {
    setQuery(item.label);
    setDestination(item);
    setIsOpen(false);
    track("DESTINATION_SELECTED", { type: item.type, label: item.label });

    // Update Recent Searches
    const getUniqueKey = (x) => x.id || x.value || x.label;
    const updatedRecent = [item, ...recentSearches.filter(r => getUniqueKey(r) !== getUniqueKey(item))].slice(0, 3);
    setRecentSearches(updatedRecent);
    localStorage.setItem('zivo_recent_searches', JSON.stringify(updatedRecent));

    // Adaptive Focus Tunneling
    onFocusNext();
  };

  const handleNearMe = () => {
    if (!navigator.geolocation) return;

    setIsLoading(true);
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        try {
          const res = await fetch(`${BASE_URL}/public/search/nearby?lat=${pos.coords.latitude}&lng=${pos.coords.longitude}`);
          if (res.ok) {
            const data = await res.json();
            if (data.length > 0) {
              handleSelect(data[0]); // Select first nearby result
            }
          }
        } catch (error) {
          console.error("Geolocation search failed", error);
        } finally {
          setIsLoading(false);
        }
      },
      (error) => {
        console.error("Geolocation denied", error);
        setIsLoading(false);
      }
    );
  };

  const getIcon = (type) => {
    switch(type) {
      case 'city': return <MapIcon className="h-4 w-4 text-brand-500" />;
      case 'hotel': return <Building className="h-4 w-4 text-brand-500" />;
      case 'area': return <MapPin className="h-4 w-4 text-brand-500" />;
      default: return <MapPin className="h-4 w-4 text-gray-400" />;
    }
  };

  // Determine what to show in dropdown
  const showEmptyState = query.length < 2 && !isLoading;
  const hasResults = suggestions.length > 0;

  return (
    <div className="flex-1 relative group" ref={wrapperRef}>
      <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1 ml-1">Destination</label>
      <div 
        className={`flex items-center border rounded-xl px-4 py-3 bg-white transition-colors focus-within:border-brand-500 focus-within:ring-2 focus-within:ring-brand-500/20 cursor-text ${error ? 'border-red-500 ring-2 ring-red-500/20' : 'border-gray-200 hover:border-brand-500'}`}
        onClick={() => setIsOpen(true)}
      >
        <Search className={`mr-3 h-5 w-5 ${error ? 'text-red-500' : 'text-brand-500'}`} />
        <input 
          type="text" 
          placeholder="City, Hotel, or Area" 
          className="w-full bg-transparent border-none outline-none text-gray-800 placeholder-gray-400 font-medium text-base"
          value={query}
          onChange={(e) => {
            setQuery(e.target.value);
            if (!isOpen) setIsOpen(true);
          }}
          onFocus={() => {
            setIsOpen(true);
            track("SEARCH_STARTED");
          }}
        />
      </div>

      {isOpen && (
        <div className="absolute z-[9999] w-full mt-2 bg-white rounded-xl shadow-2xl border border-gray-100 overflow-hidden animate-fade-in origin-top">

          {/* Near Me Option (Always Top) */}
          <div 
            onClick={handleNearMe}
            className="flex items-center px-4 py-3 cursor-pointer hover:bg-gray-50 border-b border-gray-100 transition-colors"
          >
            <div className="bg-blue-50 p-2 rounded-lg mr-3">
              <Navigation className="h-4 w-4 text-blue-600" />
            </div>
            <span className="font-semibold text-blue-600 text-sm">Use Current Location</span>
          </div>

          <div className="max-h-[300px] overflow-y-auto overscroll-contain">
            {/* Loading State: Skeletons */}
            {isLoading && (
              <div className="py-2">
                {[1, 2, 3].map(i => (
                  <div key={i} className="flex items-center px-4 py-3">
                    <div className="bg-gray-200 rounded-lg h-8 w-8 mr-3 animate-pulse"></div>
                    <div className="space-y-2 flex-1">
                      <div className="h-4 bg-gray-200 rounded w-1/3 animate-pulse"></div>
                      <div className="h-3 bg-gray-100 rounded w-1/4 animate-pulse"></div>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {/* Error State */}
            {!isLoading && fetchError && (
              <div className="flex flex-col items-center justify-center p-6 text-gray-500">
                <AlertCircle className="h-8 w-8 text-red-400 mb-2" />
                <p className="text-sm font-medium">Network error. Please try again.</p>
              </div>
            )}

